// 1. Défense de base : on s'assure que les données entrantes existent
if (!items || !Array.isArray(items)) {
  throw new Error("Erreur système : les items d'entrée sont invalides ou manquants.");
}

// 2. Extraction et filtrage ultra-robuste des produits
const products = items
  .map((item) => item?.json)
  .filter((product) => product && product.id && product.title && product.slug);

if (products.length === 0) {
  throw new Error("Aucun produit publié exploitable dans le catalogue.");
}

// 3. Fonction de classification (Piliers) avec nettoyage des espaces
const inferPillar = (title) => {
  const value = String(title || "").toLowerCase().trim();

  if (/(voiture|gps|support voiture|chargeur voiture|moto)/.test(value)) return "auto-mobilite";
  if (/(selfie|camera|capture|ring light|lumineux|photo|video|tr[eé]pied)/.test(value)) return "creation-mobile";
  if (/(coque|protection|verre|objectif|anneau de protection)/.test(value)) return "lifestyle-protection";
  if (/(chargeur|batterie|usb|magsafe|gan|c[aâ]ble|audio|ecouteur|écouteur|casque|induction)/.test(value)) return "tech-productivite";

  return "guides-achat";
};

// 4. Création des lignes du catalogue avec "Template Literals" (plus propre)
const catalogLines = products.map((product) => {
  const pillar = inferPillar(product.title);
  const price = product.retail_price ?? "N/A";
  return `- [${product.id}] ${product.title} | slug: ${product.slug} | pilier: ${pillar} | prix: ${price}€`;
});

// 5. Construction du prompt 
// /!\ CORRECTION MAJEURE : Utilisation stricte de guillemets doubles (" ") pour 
// encadrer les phrases. Cela empêche les apostrophes (ex: l'un, l'autre) de faire crasher n8n.
const prompt = [
  "Catalogue Koktek réellement vendu :",
  ...catalogLines,
  "",
  "Mission : proposer 5 sujets SEO premium strictement alignés sur ces produits exacts.",
  "Tu ne dois jamais inventer un produit, un accessoire ou un usage impossible à servir avec ce catalogue.",
  "Chaque idée doit pouvoir recommander de 1 à 4 produits exacts présents dans la liste ci-dessus.",
  "Si un angle paraît séduisant mais ne correspond à aucun produit listé, il doit être rejeté.",
  "Privilégier des sujets evergreen, utiles, inbound et réellement vendables.",
  "Favoriser en priorité les familles réellement monétisables et universelles : charge, batterie, support, mobilité auto, bureau, photo mobile, coque transparente ou antichoc, protection écran.",
  "",
  "Tu dois renvoyer UNIQUEMENT un JSON avec une clé \"ideas\" contenant un tableau de 5 objets ayant exactement ces clés :",
  "title, target_keyword, secondary_keywords, search_intent, pillar, article_type, angle, audience, brief, seasonality, priority, max_products, manual_product_ids",
  "",
  "Règles :",
  "1. title = sujet éditorial interne, clair et vendeur sans être publicitaire.",
  "2. target_keyword = requête Google plausible en français.",
  "3. pillar doit être l'un de : auto-mobilite, tech-productivite, lifestyle-protection, creation-mobile, guides-achat.",
  "4. article_type doit être l'un de : guide, checklist, comparatif, decryptage, selection, faq.",
  "5. manual_product_ids doit contenir uniquement des IDs présents dans le catalogue fourni.",
  "6. Ne jamais proposer un brassard de running, une montre ou tout autre produit absent du catalogue.",
  "7. Priorité haute si le sujet répond à un problème concret et vendable."
].join("\n");

// 6. Renvoi final sécurisé
return [{
  json: {
    products,
    product_ids: products.map((product) => String(product.id)),
    prompt,
  }
}];

// 1. Récupérer les IDs disponibles de manière sécurisée
const preparedNode = $('Code : Préparer Brief Catalogue').first();
if (!preparedNode || !preparedNode.json) {
  throw new Error("Impossible de trouver les données du catalogue précédent.");
}
const availableIds = new Set((preparedNode.json.product_ids || []).map((id) => String(id)));

// 2. Extraire le texte de l'IA (LangChain / OpenRouter)
let aiText = items[0]?.json?.output || items[0]?.json?.text || items[0]?.json?.message?.content || items[0]?.json?.message || '';

if (typeof aiText !== 'string' || !aiText.trim()) {
  throw new Error('La réponse de l\'IA est vide ou illisible.');
}

// 3. Nettoyage du markdown (les fameux ```json)
aiText = aiText.replace(/```json/gi, '').replace(/```/g, '').trim();

const start = aiText.indexOf('{');
const end = aiText.lastIndexOf('}');
const jsonSlice = start !== -1 && end !== -1 && end > start
  ? aiText.slice(start, end + 1)
  : aiText;

// 4. Double filet de sécurité pour le parsing JSON
let parsed;
try {
  parsed = JSON.parse(aiText);
} catch (e1) {
  try {
    parsed = JSON.parse(jsonSlice);
  } catch (e2) {
    throw new Error("L'IA n'a pas renvoyé un JSON valide. Réponse brute : " + aiText.substring(0, 100) + "...");
  }
}

// 5. Normalisation et filtrage des idées
const normalizeArray = (value) => Array.isArray(value) ? value : [];
const ideas = normalizeArray(parsed.ideas);
const seen = new Set();

return ideas
  .map((idea) => {
    // Ne garder que les IDs qui existent VRAIMENT dans la liste
    const ids = normalizeArray(idea.manual_product_ids)
      .map((id) => String(id))
      .filter((id) => availableIds.has(id));

    const title = String(idea.title || '').trim();
    const keyword = String(idea.target_keyword || '').trim();
    const dedupeKey = keyword.toLowerCase() || title.toLowerCase();

    // Si l'idée est vide, n'a pas de produits, ou est un doublon : on jette
    if (!title || !keyword || ids.length === 0 || seen.has(dedupeKey)) return null;
    seen.add(dedupeKey);

    return {
      json: {
        title,
        target_keyword: keyword,
        secondary_keywords: String(idea.secondary_keywords || '').trim(),
        search_intent: String(idea.search_intent || 'informational').trim() || 'informational',
        pillar: String(idea.pillar || 'guides-achat').trim() || 'guides-achat',
        article_type: String(idea.article_type || 'guide').trim() || 'guide',
        angle: String(idea.angle || '').trim(),
        audience: String(idea.audience || 'Grand public').trim() || 'Grand public',
        brief: String(idea.brief || '').trim(),
        seasonality: String(idea.seasonality || 'evergreen').trim() || 'evergreen',
        priority: parseInt(idea.priority) || 80,
        max_products: Math.min(4, Math.max(1, Number(idea.max_products || ids.length || 2))),
        manual_product_ids: JSON.stringify(ids),
        source_label: 'idea-generator',
      }
    };
  })
  .filter(Boolean)
  .slice(0, 5); // On ne garde que les 5 meilleurs
